import React, { useState, useEffect, lazy } from 'react'
import { useParams } from 'react-router';
import { Link } from 'react-router-dom';
import { API_KEY, POSTER_PATH, WIDTH_ORIGINAL, WIDTH_300, getDateShort, API_TV, count_runtime } from '../constant';
import { LazyLoadImage } from 'react-lazy-load-image-component';
import { retry } from '../utils/CommonFunctions';
const RowList = lazy(() => retry(() => import('./RowList')));
const CastList = lazy(() => retry(() => import('./CastList')));
const Keyword = lazy(() => retry(() => import('./Keyword')));
const Review = lazy(() => retry(() => import('./Review')));
const ExternalId = lazy(() => retry(() => import('./ExternalId')));
const Video = lazy(() => retry(() => import('./Video')));
const Season = lazy(() => retry(() => import('./Season')));

const Tv = () => {

  const id = useParams().id;
  const [data, setData] = useState([]);

  useEffect(() => {
    const getData = async () => {
      await fetch(API_TV + id + '?api_key=' + API_KEY)
        .then((response) => {
          return response.json();
        })
        .then((data) => {
          setData(data);
        })
        .catch((error) => {
          console.error(error);
        })
    }

    getData();
  }, [id]);

  return (
    <>
      <LazyLoadImage className="img-backdrop" src={POSTER_PATH + WIDTH_ORIGINAL + data.backdrop_path} effect="opacity" alt={data.name} onError={(e) => { e.target.onerror = null; e.target.src = "https://fakeimg.pl/500x180?retina=1&text=MoviesHub&font=bebas&font_size=15" }} />
      <div className="container">
        <div className="row">
          <div className="col-12 col-md-2">
            <LazyLoadImage className="img-poster" src={POSTER_PATH + WIDTH_300 + data.poster_path} effect="opacity" alt={data.name} onError={(e) => { e.target.onerror = null; e.target.src = "https://fakeimg.pl/300x450?text=MoviesHub&font=bebas&font_size=35" }} />
            <div className="bebasFont hide-md mt-3">{data.name}</div>
            <div>
              <div className="mt-5"><ExternalId id={id} name='tv' /></div>
              <div>{data.status ? <><div className="mt-4 text-bold">Status</div><div>{data.status}</div></> : ''}</div>
              <div>{data.type ? <><div className="mt-4 text-bold">Type</div><div>{data.type}</div></> : ''}</div>
              <div>
                {data['networks'] ? <><div className="mt-4 text-bold">Network</div><div>{data['networks'].map((dataNetwork, index) => (<span className="genre" key={index}><Link to={'/movieshub/network/' + dataNetwork.id}>{dataNetwork.name}</Link></span>))}</div></> : ''}
              </div>
              <div>{data.original_language ? <><div className="mt-4 text-bold">Language</div><div>{data.original_language}</div></> : ''}</div>
              <Keyword id={id} name='tv' />
            </div>
          </div>
          <div className="col-12 col-md-10 mt-3">
            <div className="bebasFont hide-sm">{data.name}</div>
            <div>
              {data['genres'] ? data['genres'].map((dataGenre, index) => (
                <span className="genre" key={index}>{dataGenre.name}</span>
              )) : ''}
            </div>
            <div>{getDateShort(data.first_air_date)} &#8212; {getDateShort(data.last_air_date)}</div>
            <div>Runtime: {count_runtime(data['episode_run_time'])}</div>
            <div>{data.vote_average ? data.vote_average : 'Unrated'} / 10</div>
            <div className="mt-4">{data.tagline ? '"' + data.tagline + '"' : ''}</div>
            <div>{data.overview}</div>
            <div className="mt-3">Created by: {data['created_by'] ? data['created_by'].map((dataCreated, index) => (<span className="genre" key={index}><Link to={'/movieshub/person/' + dataCreated.id}>{dataCreated.name}</Link></span>)) : 'Data not found'}</div>
            <div className="mt-3">Total Seasons: {data.number_of_seasons}</div>
            <div>Total Episodes: {data.number_of_episodes}</div>
            <div className="mt-4"><a href={data.homepage} target="_blank" rel="noreferrer"><button className="btn btn-primary">Watch Now</button></a></div>
            <Season id={id} />
            <Video id={id} name='tv' />
            <CastList id={id} name='tv' />
            <Review id={id} name='tv' />
          </div>
        </div>
        <RowList name='recommendationTv' id={id} />
        <RowList name='similarTv' id={id} />
      </div>
    </>
  )
}

export default Tv
